const items = $input.all();
const results = [];
for (const item of items) {
  const conversa = item.json;
  const mensagens = conversa.mensagens || [];
  const textoConversa = Array.isArray(mensagens)
    ? mensagens.map(m => `${m.role || 'user'}: ${m.content || m.texto || ''}`).join('\n')
    : JSON.stringify(mensagens).substring(0, 2000);
  const prompt = `Avalie a qualidade do atendimento na seguinte conversa e retorne um JSON com:\n- score_qualidade: número de 0 a 10\n- criterios: objeto com scores por critério {cordialidade, clareza, resolucao, tempo_resposta, follow_up} cada um de 0 a 10\n- boas_praticas: array de strings com boas práticas identificadas\n- pontos_melhoria: array de strings com pontos de melhoria\n- sla_cumprido: boolean\n\nConversa (score atual: ${conversa.score_qualidade || 'N/A'}):\n${textoConversa}\n\nRetorne APENAS o JSON, sem explicações.`;
  results.push({
    json: {
      ...conversa,
      prompt
    }
  });
}
return results;

const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {erro: 'parse_failed', raw: content.substring(0,200)}; }
return [{json: {...$input.first().json, resultado: parsed}}];
